var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"으윽……!","JPN":"ううっ……！","ENG":"Ngh...!","TWN":"呃……！"},"stage":{"bg":"LAB_02","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"DOCTOR_EP9HALF_NULL_NULL","text":{"KOREA":"어이구, 이 멍청한 양반아. 어째 뼈다귀들까지 주인 닮아서 자유분방한 망나니들뿐이야.","JPN":"まったく、アホったれ。骨も主に似て自由奔放なやつばかりときた。","ENG":"Ugh, you idiot... Even your bones seem to be as free-spirited as you.","TWN":"哎呀呀，你這傻小子，竟然連骨頭也跟主人一樣，都是些自由奔放的傢伙。"},"stage":{"bg":"LAB_02","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"DOCTOR_EP9HALF_NULL_NULL","text":{"KOREA":"하여튼 면허 취소되고 받는 환자 놈들은 하나같이 살기 싫은 것 같아.","JPN":"免許を取り消されてからの患者はみんな生きたくないみたいだぜ。","ENG":"After having my license revoked, it seems that every patient I see has a death wish.","TWN":"總之我的執照被吊銷後，收到的病患淨是些不想活命的傢伙。"},"stage":{"bg":"LAB_02","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"……떠들 시간에 마취나 잘해 주지. 살 째는 감각이 생생하던데.","JPN":"……しゃべってる間にちゃんと麻酔してくれ。肌を切る感覚がそのまま感じられるんだが。","ENG":"...How about less scolding and more painkillers? I could feel the blade running across my skin and bone.","TWN":"……在你囉嗦的同時可以幫我打個麻醉嗎？我完全可以感受到你在切我的肉欸？"},"stage":{"bg":"LAB_02","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"DOCTOR_EP9HALF_NULL_NULL","text":{"KOREA":"말 걸지 마, 정신 사납게. 내 손 미끄러지면 너 평생 휠체어 타고 다니는 거야.","JPN":"話しかけんな、気が散る。俺の手が滑ったらお前さんは一生車椅子生活だぞ。","ENG":"Stop talking, I can't concentrate! If I make a mistake, you'll be in a wheelchair for the rest of your life.","TWN":"別和我說話，我要專心。要是我一個手滑，你可能下半輩子就要坐輪椅囉。"},"stage":{"bg":"LAB_02","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"……","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HOSPITAL","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L13_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"표정이 왜 그래요, 언니? 대장이 잘못될까 봐 그래?","JPN":"どうしてそんな顔してるんですか、ユリさん？　隊長が心配だから？","ENG":"What's wrong, Yuri? Are you worried about Captain?","TWN":"姊姊，你怎麼那副表情？是擔心隊長出什麼事嗎？"},"stage":{"bg":"HOSPITAL","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"아니. 좀 생각할 게 있었어.","JPN":"いや。ちょっと思うところがあって。","ENG":"No, I just have a lot on my mind.","TWN":"不是，我在想其他事。"},"stage":{"bg":"HOSPITAL","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"대장 수술 끝나면 너도 가서 진료 받아. 알파트릭스 녀석들과 싸울 때 총에 맞았잖아.","JPN":"隊長の手術が終わったらあなたも診察を受けな。アルファトリックスのやつらと戦ってる時に銃に撃たれただろ。","ENG":"Once he's done, you should get that gunshot wound checked as well.","TWN":"等隊長手術結束後，你也去治療一下吧。和阿爾法崔克斯的傢伙打鬥時你不是也有中槍嗎？"},"stage":{"bg":"HOSPITAL","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"헤헷, 그거라면 걱정 마요. 언니.","JPN":"へへっ、それなら心配ご無用です。","ENG":"Hehe, you don't have to worry about me.","TWN":"嘿嘿，這你不用擔心啦，姊姊。"},"stage":{"bg":"HOSPITAL","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L18_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"여기 보다시피 다……","JPN":"ほら、見てのとおり全部……","ENG":"As you can see, I'm all─","TWN":"你看，這裡都……"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"언니? 왜 갑자기 총을 다 겨누고 그래, 무섭게.","JPN":"ユリさん？　なんでいきなり銃を構えるんですか？　怖いですよ。","ENG":"Yuri? Why are you pointing a gun at me? It's scaring me...","TWN":"姊姊？為何突然拿槍指著我？好嚇人喔。"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"……생각 중이었어. 같이 폭발에 휘말린 대장은 저렇게 골골거리는데, 넌 왜 멀쩡한지.","JPN":"……考えてたんだ。一緒に爆発に巻き込まれた隊長はああなったのに、なんでお前はなんともないのか。","ENG":"I've been thinking. Both you and Captain were caught in the blast. But he's barely alive, while you're not even scathed.","TWN":"……我一直在想，你和隊長明明就是同時被爆炸波及，為何隊長傷得那麼嚴重，你卻一點事都沒有？"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"답은 의외로 가까이 있더군.","JPN":"答えは以外と簡単だった。","ENG":"Turns out the answer wasn't too far away.","TWN":"沒想到答案這麼簡單。"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"카운터라서?","JPN":"カウンターだから？","ENG":"Because I'm a Counter?","TWN":"因為我是制裁者嗎？"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"맞아. 그리고 넌 여지껏 네가 카운터라는 말은 한마디도 하지 않았지.","JPN":"そう。それにお前は今まで自分がカウンターだなんてことは一言も言わなかった。","ENG":"Yeah. And you haven't said a word about it.","TWN":"沒錯，你至今從未提起你是制裁者的事吧？"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"카운터를 사냥하는 사람들에게 카운터라고 밝혀 봤자 좋을 것 없잖아.","JPN":"カウンターを狩る人たちにカウンターって言ってもいいことないでしょ。","ENG":"Well, I don't think it's necessary to tell Counter-hunters that I'm a Counter as well, right?","TWN":"告訴專門獵殺制裁者的人我是制裁者，這件事完全沒好處的嘛。"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"애초에 의뢰인을 덜컥 죽인 것도 수상해.","JPN":"そもそも依頼人を殺したことも怪しい。","ENG":"Also, it's suspicious that you killed our client just like that.","TWN":"先前突然殺掉委託人也可疑。"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};